   531→          pmBlockedCount: result.blockedFromPmTrainIds.length,
   532→          runBlockedCount: result.blockedFromRunAssignmentTrainIds.length,
   533→        },
   534→        'Optimizer constraints from active unavailability events'
   535→      );
   536→
   537→      return result;
   538→    });
